import{k as t,H as e}from"./index.Bzfkn_Jf.js";const r=window.location.pathname.split("/verify/")[1],n=document.querySelector("#info-dot");setInterval(()=>{n.innerHTML.length<3?n.innerHTML=n.innerHTML+".":n.innerHTML="."},500);(async()=>{try{await t.patch("/api/auth/verify/",{json:{token:r}}).json(),location.assign("/login")}catch(o){o instanceof e&&console.log(o.data.error)}})();
